const processedResults = [];
const allItems = $input.all();

for (let i = 0; i < allItems.length; i++) {
  const item = allItems[i];
  if (item.binary) {
    const binaryKeys = Object.keys(item.binary);
    for (const key of binaryKeys) {
      try {
        // Use the helper function to read and force-convert to a string to prevent garbled characters.
        const binaryBuffer = await this.helpers.getBinaryDataBuffer(i, key);
        const rawCode = binaryBuffer.toString('utf-8');

        if (rawCode.length > 0) {
          processedResults.push({
            json: {
              code: rawCode,
              fileName: item.binary[key].fileName || `${key}.sol`
            }
          });
        }
      } catch (e) { console.error(e.message); }
    }
  }
}
return processedResults;

return items.map(item => {
  return {
    json: {
      tool: "ChainGPT",
      file_name: item.json.fileName || item.json.filename || "unknown.sol",
      status: "success",
      raw_response: item.json.data ?? item.json,
      timestamp: new Date().toISOString()
    }
  };
});

const input = $input.item.json || {};

const fileName =
  input.fileName ||
  input.filename ||
  input.file_name ||
  input.name ||
  input.originalFileName ||
  input.original_filename ||
  $('Data Preprocessing & Aggregation').first().json.fileName ||
  $('On form submission').first().json.fileName ||
  'unknown.sol';

const issues = input.data?.issues || input.issues || [];
const error = input.data?.error ?? input.error ?? null;
const status =
  input.status ||
  (input.data?.success === true ? 'success' : 'unknown');

const tool = input.tool || 'Mythril';

return [{
  json: {
    tool,
    file_name: fileName,
    status,
    error,
    issues,
    raw_output: input,
    timestamp: new Date().toISOString()
  }
}];

const data = $input.first().json;

const paragraphs = String(data.raw_response || "")
  .split(/\n\s*\n/)
  .map(p => p.trim())
  .filter(Boolean);

const pretty = {
  tool: data.tool,
  file_name: data.file_name,
  status: data.status,
  raw_response_paragraphs: paragraphs,
  timestamp: data.timestamp
};

const content = JSON.stringify(pretty, null, 2);

return [
  {
    json: {},
    binary: {
      file: {
        data: Buffer.from(content, "utf8").toString("base64"),
        mimeType: "application/json",
        fileName: "chaingpt_log_pretty.json"
      }
    }
  }
];

const data = $input.item.json || {};
const jsonText = JSON.stringify(data, null, 2);

return [{
  json: {
    success: true,
    preview: 'Mythril log JSON generated'
  },
  binary: {
    data: {
      data: Buffer.from(jsonText, 'utf8').toString('base64'),
      mimeType: 'application/json',
      fileName: 'mythril_log.json'
    }
  }
}];

const normalizedFindings = [];
const rawToolOutputs = {};
let toolCount = 0;

// Filter obvious engineering suggestions that should not be treated as vulnerabilities
function isLikelyNonVulnerability(text) {
  const t = String(text).toLowerCase();
  const patterns = [
    "consider adding events",
    "improve transparency",
    "gas optimization",
    "documentation",
    "best practice",
    "testing is recommended",
    "consider thorough testing",
    "lack of events",
    "fallback or receive function",
    "forced ether reception"
  ];
  return patterns.some(p => t.includes(p));
}

// Split ChainGPT long text into candidate claims
function extractChainClaims(text) {
  const raw = String(text || "").trim();
  if (!raw) return [];

  const parts = raw
    .split(/\n(?=\d+\.\s|\-\s|\*\*Issue|\*\*Recommendation|###|####)/)
    .map(s => s.trim())
    .filter(Boolean);

  const claims = [];

  for (const part of parts) {
    if (isLikelyNonVulnerability(part)) {
      claims.push({
        tool: "ChainGPT",
        type: "engineering_suggestion",
        status: "unsupported_as_vulnerability",
        confidence: "low",
        content: part
      });
    } else {
      claims.push({
        tool: "ChainGPT",
        type: "candidate_claim",
        status: "unverified",
        confidence: "low",
        content: part
      });
    }
  }

  return claims;
}

// Read ChainGPT output
try {
  const chainNode = $("ChainGPT check").first();
  if (chainNode && chainNode.json && chainNode.json.data) {
    toolCount++;
    rawToolOutputs.ChainGPT = chainNode.json.data;

    const chainClaims = extractChainClaims(chainNode.json.data);
    normalizedFindings.push(...chainClaims);
  }
} catch (e) {
  normalizedFindings.push({
    tool: "ChainGPT",
    type: "tool_error",
    status: "failed",
    confidence: "high",
    content: "ChainGPT read failed"
  });
}

// Build summary text
const summaryText = normalizedFindings.map((f, idx) => {
  return [
    `Finding #${idx + 1}`,
    `tool: ${f.tool}`,
    `type: ${f.type}`,
    `status: ${f.status}`,
    `confidence: ${f.confidence || "unknown"}`,
    `content: ${f.content || ""}`
  ].filter(Boolean).join("\n");
}).join("\n\n--------------------\n\n");

const keywordsText = summaryText.toLowerCase();

// Generate routing tags
const tags = [];
if (keywordsText.includes("reentrancy")) tags.push("reentrancy");
if (
  keywordsText.includes("access control") ||
  keywordsText.includes("onlyowner") ||
  keywordsText.includes("owner check") ||
  keywordsText.includes("unprotected function") ||
  keywordsText.includes("init")
) tags.push("access_control");
if (keywordsText.includes("tx.origin")) tags.push("tx_origin");
if (
  keywordsText.includes("approve") ||
  keywordsText.includes("allowance") ||
  keywordsText.includes("approval")
) tags.push("approval_risk");
if (
  keywordsText.includes("overflow") ||
  keywordsText.includes("underflow") ||
  keywordsText.includes("unchecked")
) tags.push("arithmetic");
if (keywordsText.includes("event")) tags.push("event_suggestion");

return {
  summary: summaryText || "No findings or tool execution issues detected",
  keywords: keywordsText,
  tool_count: toolCount,
  normalized_findings: normalizedFindings,
  raw_tool_outputs: rawToolOutputs,
  tags: [...new Set(tags)]
};

