const input = $input.item.json || {};

const rawData = input.data || {};
const rawIssues = Array.isArray(rawData.issues)
  ? rawData.issues
  : Array.isArray(input.issues)
    ? input.issues
    : [];

const toolName = input.tool || 'Mythril';
const status = input.status || (rawData.success ? 'success' : 'unknown');
const toolCount = 1;

function norm(v) {
  return String(v || '').trim();
}

function lower(v) {
  return norm(v).toLowerCase();
}

function buildTitle(issue) {
  if (issue.title) return norm(issue.title);

  const description = norm(issue.description);
  if (!description) return 'Untitled Mythril Finding';

  return description.split('\n')[0].slice(0, 120);
}

function buildContent(issue) {
  const parts = [
    issue.address !== undefined ? `"address": ${JSON.stringify(issue.address)}` : null,
    issue.code ? `"code": ${JSON.stringify(issue.code)}` : null,
    issue.contract ? `"contract": ${JSON.stringify(issue.contract)}` : null,
    issue.function ? `"function": ${JSON.stringify(issue.function)}` : null,
    issue.description ? `"description": ${JSON.stringify(issue.description)}` : null,
    issue.severity ? `"severity": ${JSON.stringify(issue.severity)}` : null,
    issue.swc_id ? `"swc_id": ${JSON.stringify(issue.swc_id)}` : null
  ].filter(Boolean);

  return `{ ${parts.join(', ')} }`;
}

const normalizedFindings = rawIssues.map((issue, index) => {
  const title = buildTitle(issue);
  const severity = norm(issue.severity || 'Unknown');
  const confidence = norm(issue.confidence || 'high');
  const description = norm(issue.description || '');
  const contract = norm(issue.contract || '');
  const fn = norm(issue.function || '');
  const code = norm(issue.code || '');
  const swcId = norm(issue.swc_id || '');

  return {
    tool: toolName,
    type: 'scanner_finding',
    status: 'reported',
    confidence: confidence.toLowerCase(),
    issue_index: index,
    title,
    content: buildContent(issue),
    severity,
    contract,
    function: fn,
    code,
    swc_id: swcId,
    raw: issue
  };
});

const summaryText = normalizedFindings.length
  ? normalizedFindings.map((f, idx) => {
      return [
        `Finding #${idx + 1}`,
        `tool: ${f.tool}`,
        `type: ${f.type}`,
        `status: ${f.status}`,
        `confidence: ${f.confidence}`,
        `title: ${f.title}`,
        `content: ${f.content}`
      ].join('\n');
    }).join('\n\n')
  : `${toolName} executed successfully and reported zero findings.`;

const keywordsText = normalizedFindings.length
  ? normalizedFindings.map(f => {
      return [
        f.title,
        f.content,
        f.contract,
        f.function,
        f.code,
        f.swc_id,
        f.severity
      ].filter(Boolean).join(' ');
    }).join(' ')
  : `${toolName} executed successfully and reported zero findings.`;

const tags = [];
const keywordsLower = lower(keywordsText);

if (!normalizedFindings.length) {
  tags.push('no_findings');
}

if (
  keywordsLower.includes('reentrancy') ||
  keywordsLower.includes('re-enter')
) {
  tags.push('reentrancy');
}

if (
  keywordsLower.includes('external call') ||
  keywordsLower.includes('user-supplied address') ||
  keywordsLower.includes('call to a user-supplied address')
) {
  tags.push('external_call');
}

if (
  keywordsLower.includes('call return value') ||
  keywordsLower.includes('unchecked') ||
  keywordsLower.includes('return value')
) {
  tags.push('unchecked_call');
}

if (
  keywordsLower.includes('overflow') ||
  keywordsLower.includes('underflow') ||
  keywordsLower.includes('integer') ||
  keywordsLower.includes('arithmetic')
) {
  tags.push('arithmetic');
}

if (
  keywordsLower.includes('access control') ||
  keywordsLower.includes('authorization') ||
  keywordsLower.includes('owner') ||
  keywordsLower.includes('onlyowner') ||
  keywordsLower.includes('role')
) {
  tags.push('access_control');
}

if (keywordsLower.includes('tx.origin')) {
  tags.push('tx_origin');
}

if (keywordsLower.includes('delegatecall')) {
  tags.push('delegatecall');
}

if (
  keywordsLower.includes('selfdestruct') ||
  keywordsLower.includes('suicide')
) {
  tags.push('selfdestruct');
}

if (
  keywordsLower.includes('timestamp') ||
  keywordsLower.includes('block.timestamp')
) {
  tags.push('timestamp_dependence');
}

if (
  keywordsLower.includes('file not found') ||
  keywordsLower.includes('parsererror') ||
  keywordsLower.includes('fatal error') ||
  status === 'failed' ||
  rawData.error
) {
  tags.push('tool_failure');
}

return [{
  json: {
    summary: summaryText || 'No Mythril output detected',
    keywords: keywordsText,
    tool_count: toolCount,
    normalized_findings: normalizedFindings,
    raw_tool_outputs: {
      Mythril: input
    },
    tags: [...new Set(tags)]
  }
}];

