function cleanJsonText(text) {
  return String(text || '')
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/, '')
    .trim();
}

let parsed;
try {
  parsed = JSON.parse(cleanJsonText(raw));
} catch (e) {
  parsed = {
    candidate_findings: [],
    notes: 'Failed to parse Claim Evaluator output.',
    raw_total_findings: 0,
    retained_findings: 0,
    filtered_findings: 0,
    filtering_rate: 0
  };
}

