const filtered = Number(
  parsed.filtered_findings ??
  Math.max(rawTotal - retained, 0)
);
const filteringRate = rawTotal > 0 ? filtered / rawTotal : 0;

return [{
  json: {
    candidate_findings: parsed.candidate_findings,
    notes: parsed.notes || '',
